import React, { useState, useRef, useEffect, useMemo } from 'react';
import Fuse from 'fuse.js';
import { motion, AnimatePresence } from 'framer-motion';
import {
  MessageSquare,
  Search,
  History,
  Mic,
  Square,
  Play,
  Sparkles,
  Trash2,
  Calendar,
  ChevronRight
} from 'lucide-react';
import './index.css';

function App() {
  const [gravando, setGravando] = useState(false);
  const [transcricao, setTranscricao] = useState('');
  const [exercicio, setExercicio] = useState('');
  const [carregando, setCarregando] = useState(false);
  const [historico, setHistorico] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [sessaoAtiva, setSessaoAtiva] = useState(null);

  const mediaRecorderRef = useRef(null);
  const audioChunksRef = useRef([]);

  // Carregar histórico ao iniciar
  useEffect(() => {
    fetchHistorico();
  }, []);

  const fetchHistorico = async () => {
    try {
      const resp = await fetch('http://localhost:5000/historico');
      const data = await resp.json();
      setHistorico(data.map(item => ({
        ...item,
        sentimento: item.sentimento || 'Neutro'
      })));
    } catch (err) {
      console.error("Erro ao carregar histórico:", err);
    }
  };

  const [falando, setFalando] = useState(false);

  // Prepara as vozes do sistema (essencial para Chrome/Brave)
  useEffect(() => {
    const carregarVozes = () => window.speechSynthesis.getVoices();
    carregarVozes();
    if (window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = carregarVozes;
    }
  }, []);

  const falar = (texto) => {
    if (!texto || !('speechSynthesis' in window)) return;

    window.speechSynthesis.cancel();
    window.speechSynthesis.resume();

    const mensagemPura = texto
      .replace(/ANALISE:/g, 'Perspectiva clínica: ')
      .replace(/SESSAO:/g, 'Tópicos para levar ao seu psicólogo: ')
      .replace(/ACAO:/g, 'Sugestão de ação imediata: ')
      .replace(/[*#=_\-]/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();

    const chunks = mensagemPura.match(/.{1,200}(?:\s|$)/g) || [mensagemPura];
    let currentChunk = 0;

    const speakNextChunk = () => {
      if (currentChunk >= chunks.length) {
        setFalando(false);
        return;
      }

      const locutor = new SpeechSynthesisUtterance(chunks[currentChunk]);
      const vozes = window.speechSynthesis.getVoices();

      // Prioridade por vozes mais suaves/naturais (Neural ou Google)
      const vozCalma = vozes.find(v => v.name.includes('Neural') && v.lang.includes('pt-BR')) ||
        vozes.find(v => v.name.includes('Google') && v.lang.includes('pt-BR')) ||
        vozes.find(v => v.lang.includes('pt-BR'));

      if (vozCalma) locutor.voice = vozCalma;
      locutor.lang = 'pt-BR';
      locutor.rate = 0.85;  // Mais lento para passar calma
      locutor.pitch = 1.05; // Levemente acolhedor
      locutor.volume = 0.9;

      locutor.onstart = () => {
        console.log(`Falando calmamente parte ${currentChunk + 1}`);
        setFalando(true);
      };

      locutor.onend = () => {
        currentChunk++;
        setTimeout(speakNextChunk, 700); // Pausa reflexiva entre frases
      };

      locutor.onerror = () => setFalando(false);
      window.speechSynthesis.speak(locutor);
    };

    speakNextChunk();
  };

  const pararDeFalar = () => {
    window.speechSynthesis.cancel();
    setFalando(false);
  };

  const deleteSessao = async (e, id) => {
    e.stopPropagation();
    if (!window.confirm("Deseja apagar este registro do histórico?")) return;

    try {
      await fetch(`http://localhost:5000/sessao/${id}`, { method: 'DELETE' });
      fetchHistorico();
      if (sessaoAtiva?.id === id) {
        setTranscricao('');
        setExercicio('');
        setSessaoAtiva(null);
      }
    } catch (err) {
      console.error("Erro ao deletar:", err);
    }
  };

  const getSentimentClass = (sentimento) => {
    const s = sentimento.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
    return `sentiment-${s}`;
  };

  // Configuração da Busca Dinâmica (Fuse.js)
  const filteredHistorico = useMemo(() => {
    if (!searchTerm) return historico;
    const fuse = new Fuse(historico, {
      keys: ['transcricao', 'exercicio', 'sentimento'],
      threshold: 0.4
    });
    return fuse.search(searchTerm).map(result => result.item);
  }, [historico, searchTerm]);

  const iniciarGravacao = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new window.MediaRecorder(stream);
      audioChunksRef.current = [];
      mediaRecorderRef.current = mediaRecorder;

      mediaRecorder.ondataavailable = (e) => audioChunksRef.current.push(e.data);

      mediaRecorder.onstop = async () => {
        setCarregando(true);
        const audioBlob = new Blob(audioChunksRef.current);
        const formData = new FormData();
        formData.append('audio', audioBlob, 'sessao.mp3');

        try {
          const resposta = await fetch('http://localhost:5000/transcribe', {
            method: 'POST',
            body: formData
          });
          const dados = await resposta.json();
          setTranscricao(dados.transcricao);

          const respostaExercicio = await fetch('http://localhost:5000/sugerir-exercicio', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ transcricao: dados.transcricao })
          });
          const exercicioData = await respostaExercicio.json();
          setExercicio(exercicioData.exercicio);

          // Falar a resposta automaticamente
          falar(exercicioData.exercicio);

          // Atualizar histórico após nova sessão
          fetchHistorico();
        } catch (error) {
          console.error("Erro ao processar áudio:", error);
          setTranscricao("Erro na conexão com o assistente.");
        } finally {
          setCarregando(false);
        }
      };

      mediaRecorder.start();
      setGravando(true);
      setTranscricao('');
      setExercicio('');
      setSessaoAtiva(null);
      window.speechSynthesis.cancel();
    } catch (err) {
      console.error("Erro ao acessar microfone:", err);
      alert("Por favor, permita o acesso ao microfone.");
    }
  };

  const pararGravacao = () => {
    if (mediaRecorderRef.current) {
      mediaRecorderRef.current.stop();
      setGravando(false);
      mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
    }
  };

  const selecionarSessao = (sessao) => {
    setSessaoAtiva(sessao);
    setTranscricao(sessao.transcricao);
    setExercicio(sessao.exercicio);
    falar(sessao.exercicio);
  };

  const formatarAnalise = (texto) => {
    if (!texto) return null;

    // Divide o texto em seções usando os marcadores
    const analiseMatch = texto.match(/ANALISE:([\s\S]*?)(?=SESSAO:|$)/);
    const sessaoMatch = texto.match(/SESSAO:([\s\S]*?)(?=ACAO:|$)/);
    const acaoMatch = texto.match(/ACAO:([\s\S]*?)$/);

    const sections = {
      analise: analiseMatch ? analiseMatch[1].trim() : texto,
      sessao: sessaoMatch ? sessaoMatch[1].trim() : '',
      acao: acaoMatch ? acaoMatch[1].trim() : ''
    };

    return (
      <div className="professional-analysis">
        {sections.analise && (
          <div className="analysis-section">
            <h4><ChevronRight size={14} /> Perspectiva Clínica</h4>
            <p>{sections.analise}</p>
          </div>
        )}
        {sections.sessao && (
          <div className="analysis-section preparation">
            <h4><ChevronRight size={14} /> Tópicos para sua Sessão</h4>
            <ul>
              {sections.sessao.split('\n').map((line, i) => line.trim() && (
                <li key={i}>{line.replace(/^[-*]\s*/, '')}</li>
              ))}
            </ul>
          </div>
        )}
        {sections.acao && (
          <div className="analysis-section action">
            <h4><ChevronRight size={14} /> Ação Recomendada</h4>
            <p>{sections.acao}</p>
          </div>
        )}
      </div>
    );
  };

  const copiarParaPsicologo = () => {
    const resumo = `
RESUMO PARA O PSICÓLOGO
-----------------------
DATA: ${sessaoAtiva?.data || new Date().toLocaleString()}
DESABAFO: ${transcricao}
-----------------------
ANÁLISE IA:
${exercicio}
    `;
    navigator.clipboard.writeText(resumo);
    alert("Resumo copiado com sucesso!");
  };

  return (
    <div className="app-wrapper">
      {/* Sidebar - Busca Dinâmica */}
      <aside className="sidebar">
        <div className="sidebar-header">
          <h2><History size={24} /> Seu Histórico</h2>
          <div className="search-container">
            <Search className="search-icon" size={18} />
            <input
              type="text"
              placeholder="Busca dinâmica..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="history-list">
          {filteredHistorico.map((item) => (
            <motion.div
              key={item.id}
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              className={`history-item ${sessaoAtiva?.id === item.id ? 'active' : ''}`}
              onClick={() => selecionarSessao(item)}
            >
              <div className="history-item-content">
                <div className="date">
                  {item.data} • <span className={`sentiment-tag ${getSentimentClass(item.sentimento)}`}>{item.sentimento}</span>
                  <button className="delete-btn" onClick={(e) => deleteSessao(e, item.id)}>
                    <Trash2 size={14} />
                  </button>
                </div>
                <div className="preview">{item.transcricao}</div>
              </div>
            </motion.div>
          ))}
          {filteredHistorico.length === 0 && (
            <div className="status-text" style={{ textAlign: 'center', marginTop: '2rem' }}>
              Nenhum registro encontrado
            </div>
          )}
        </div>
      </aside>

      {/* Main Content */}
      <main className="main-content">
        <div className="app-container">
          <header className="header">
            <motion.h1
              initial={{ opacity: 0, y: -20 }}
              animate={{ opacity: 1, y: 0 }}
            >
              Psicólogo IA
            </motion.h1>
            <p className="status-text">Seu suporte profissional e preparação para terapia</p>
          </header>

          <motion.div
            className="main-card"
            layout
          >
            <section className="record-section">
              <button
                className={`pulse-button ${gravando ? 'recording' : ''}`}
                onClick={gravando ? pararGravacao : iniciarGravacao}
                disabled={carregando}
              >
                {gravando ? <Square size={48} /> : <Mic size={48} />}
              </button>
              <div className="status-container">
                <span className="status-text">
                  {gravando ? 'Ouvindo desabafo...' : carregando ? 'Gerando análise clínica...' : 'Clique para começar a falar'}
                </span>
              </div>
            </section>

            <AnimatePresence mode="wait">
              {(transcricao || exercicio || carregando) && (
                <motion.section
                  className="result-section"
                  initial={{ opacity: 0, opacity: 0 }}
                  animate={{ opacity: 1, opacity: 1 }}
                  exit={{ opacity: 0, opacity: 0 }}
                >
                  <div className="result-card">
                    <h3><MessageSquare size={14} style={{ marginRight: 8 }} /> Seu Desabafo</h3>
                    <p>{carregando && !transcricao ? <span className="loading-dots">Transcrevendo áudio</span> : transcricao}</p>
                  </div>

                  {(exercicio || carregando) && (
                    <motion.div
                      className="result-card professional-card"
                      initial={{ opacity: 0, x: 20 }}
                      animate={{ opacity: 1, x: 0 }}
                    >
                      <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                        <h3 style={{ margin: 0, display: 'flex', alignItems: 'center' }}>
                          <Sparkles size={14} style={{ marginRight: 8 }} /> Análise e Preparação
                        </h3>
                        <div className="card-actions" style={{ display: 'flex', gap: '8px' }}>
                          {exercicio && (
                            <>
                              <button
                                onClick={copiarParaPsicologo}
                                className="audio-control-btn"
                                title="Copiar Resumo para o Psicólogo"
                                style={{ background: 'rgba(255,255,255,0.1)' }}
                              >
                                <Calendar size={16} />
                              </button>
                              <button
                                onClick={falando ? pararDeFalar : () => falar(exercicio)}
                                className="audio-control-btn"
                                title={falando ? "Parar áudio" : "Ouvir resposta"}
                              >
                                {falando ? <Square size={16} fill="currentColor" /> : <Play size={16} fill="currentColor" />}
                              </button>
                            </>
                          )}
                        </div>
                      </div>
                      <div className="analysis-content">
                        {carregando && !exercicio ? (
                          <span className="loading-dots">Consultando abordagem terapêutica</span>
                        ) : (
                          formatarAnalise(exercicio)
                        )}
                      </div>
                    </motion.div>
                  )}
                </motion.section>
              )}
            </AnimatePresence>
          </motion.div>
        </div>
      </main>
    </div>
  );
}

export default App;
